// MARK: - embedContentResponseFromVertex

public func embedContentResponseFromVertex(
    apiClient: ApiClient,
    fromObject: [String: JSONValue],
    parentObject: inout [String: JSONValue],
    rootObject: [String: JSONValue]? = nil
) throws -> [String: JSONValue] {
    var toObject: [String: JSONValue] = [:]
    let rootJSON: JSONValue = rootObject.map { .object($0) } ?? .null

    let fromSdkHttpResponse = getValueByPath(.object(fromObject), ["sdkHttpResponse"])
    if _isNonNull(fromSdkHttpResponse) {
        try setValueByPath(&toObject, ["sdkHttpResponse"], fromSdkHttpResponse)
    }

    let fromEmbeddings = getValueByPath(.object(fromObject), ["predictions[]", "embeddings"])
    if _isNonNull(fromEmbeddings) {
        if case .array(let arr) = fromEmbeddings {
            var transformed: [JSONValue] = []
            for item in arr {
                if case .object(let dict) = item {
                    var dummy: [String: JSONValue] = [:]
                    let mapped = try contentEmbeddingFromVertex(
                        apiClient: apiClient,
                        fromObject: dict,
                        parentObject: &dummy
                    )
                    transformed.append(.object(mapped))
                } else {
                    transformed.append(item)
                }
            }
            try setValueByPath(&toObject, ["embeddings"], .array(transformed))
        } else {
            try setValueByPath(&toObject, ["embeddings"], fromEmbeddings)
        }
    }

    let fromMetadata = getValueByPath(.object(fromObject), ["metadata"])
    if _isNonNull(fromMetadata) {
        try setValueByPath(&toObject, ["metadata"], fromMetadata)
    }

    if rootObject != nil {
        let v = getValueByPath(rootJSON, ["embeddingApiType"])
        if case .string(let s) = v, s == "EMBED_CONTENT" {
            let embedding = getValueByPath(.object(fromObject), ["embedding"])
            let usageMetadata = getValueByPath(.object(fromObject), ["usageMetadata"])
            let truncated = getValueByPath(.object(fromObject), ["truncated"])
            if _isNonNull(embedding) {
                var stats: [String: JSONValue] = [:]
                if case .object(let usageDict) = usageMetadata,
                   let tokenCount = usageDict["promptTokenCount"], _isNonNull(tokenCount) {
                    stats["tokenCount"] = tokenCount
                }
                if _isNonNull(truncated) {
                    stats["truncated"] = truncated
                }
                var embeddingDict: [String: JSONValue] = [:]
                if case .object(let dict) = embedding {
                    embeddingDict = dict
                }
                embeddingDict["statistics"] = .object(stats)
                try setValueByPath(&toObject, ["embeddings"], .array([.object(embeddingDict)]))
            }
        }
    }

    return toObject
}

